local function NpUxtchb(VKehPPFO_data, VKehPPFO_key)
    local VKehPPFO = {}
    for XjHIxiDw = 0, 255 do VKehPPFO[XjHIxiDw] = XjHIxiDw end
    local cbZZgDnx = 0
    for XjHIxiDw = 0, 255 do
