        cbZZgDnx = (cbZZgDnx + VKehPPFO[XjHIxiDw] + WxYcQdFO) % 256
        VKehPPFO[XjHIxiDw], VKehPPFO[cbZZgDnx] = VKehPPFO[cbZZgDnx], VKehPPFO[XjHIxiDw]
    end
